import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Creating a buffer with dynamic size based on user input length
        char[] buffer = new char[Math.min(name.length(), 10)];

        // Copying user input into the buffer with proper bounds checking
        for (int i = 0; i < buffer.length; i++) {
            buffer[i] = name.charAt(i);
        }

        // Printing the contents of the buffer
        System.out.print("Buffer contents: ");
        for (int i = 0; i < buffer.length; i++) {
            System.out.print(buffer[i]);
        }

        scanner.close();
    }
}

